  import java.util.HashMap;
  import java.util.Map;
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  import sailpoint.tools.Util;
  
  Map returnMap = new HashMap();

  if(account != null){

    String employeeID = null;
    String oprID = null;


    if(account.getAttribute("EMPLID") != null){
      employeeID = (String) account.getAttribute("EMPLID");
    }
    if(account.getAttribute("OPRID") != null){
      oprID = (String) account.getAttribute("OPRID");
    }

    if(Util.isNotNullOrEmpty(employeeID)){

      QueryOptions qo = new QueryOptions();
      Filter f = Filter.eq("employeeId", employeeID);
      Filter caseFilter = Filter.ignoreCase(f);
      qo.addFilter(caseFilter);
      Iterator it = context.search(Identity.class, qo, "name");

      while(it.hasNext()){
        String identityName = (String)it.next()[0];
        returnMap.put("identityName", identityName);
        break;
      }
    }

    if(Util.isNotNullOrEmpty(oprID) && Util.isEmpty(returnMap)){

      QueryOptions qo = new QueryOptions();
      Filter f = Filter.eq("samAccountName", oprID);
      Filter caseFilter = Filter.ignoreCase(f);
      qo.addFilter(caseFilter);
      Iterator it = context.search(Identity.class, qo);

      while(it.hasNext()){
        Identity identity = it.next();
        String ministry = identity.getAttribute("ministry");

        if(!Util.nullSafeCaseInsensitiveEq(ministry, "AMITA Health")){
          returnMap.put("identityName", identity.getName());
        }
        break;
      }

    }
  }

  return returnMap;
